#!/usr/bin/env python3\n\"\"\"\nTest script to validate AI response quality for educational content\n\"\"\"\n\nimport asyncio\nimport sys\nimport os\nsys.path.append(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))\n\nfrom app.agents.tools.openai_tool import OpenAITool\nfrom app.agents.nodes.tutor_agent import TutorAgent\nfrom app.agents.nodes.assessment_agent import AssessmentAgent\nfrom app.db.session import SessionLocal\nimport json\nimport re\nfrom typing import Dict, List, Any\n\nclass AIQualityValidator:\n    \"\"\"Validates the quality of AI-generated educational content\"\"\"\n    \n    def __init__(self):\n        self.openai_tool = OpenAITool()\n        self.db = SessionLocal()\n        self.tutor_agent = TutorAgent()\n        self.assessment_agent = AssessmentAgent()\n    \n    def validate_lesson_content(self, topic: str) -> Dict[str, Any]:\n        \"\"\"Validate the quality of AI-generated lesson content\"\"\"\n        print(f\"\\n📚 Validating lesson content for: {topic}\")\n        \n        try:\n            # Generate lesson content\n            lesson_data = {\n                \"topic_name\": topic,\n                \"user_level\": \"beginner\",\n                \"learning_style\": \"balanced\"\n            }\n            \n            lesson = self.tutor_agent.generate_lesson(lesson_data)\n            \n            # Validation criteria\n            validations = {\n                \"has_required_sections\": self._validate_lesson_structure(lesson),\n                \"content_quality\": self._validate_content_quality(lesson),\n                \"code_examples\": self._validate_code_examples(lesson),\n                \"educational_value\": self._validate_educational_value(lesson),\n                \"language_clarity\": self._validate_language_clarity(lesson)\n            }\n            \n            # Calculate overall score\n            scores = [v[\"score\"] for v in validations.values()]\n            overall_score = sum(scores) / len(scores)\n            \n            return {\n                \"topic\": topic,\n                \"overall_score\": overall_score,\n                \"validations\": validations,\n                \"passed\": overall_score >= 0.8,\n                \"lesson_content\": lesson\n            }\n            \n        except Exception as e:\n            return {\n                \"topic\": topic,\n                \"error\": str(e),\n                \"passed\": False\n            }\n    \n    def validate_assessment_questions(self, topic: str, question_count: int = 4) -> Dict[str, Any]:\n        \"\"\"Validate the quality of AI-generated assessment questions\"\"\"\n        print(f\"\\n📝 Validating assessment questions for: {topic}\")\n        \n        try:\n            # Generate assessment questions\n            assessment_data = {\n                \"topic_name\": topic,\n                \"difficulty\": \"medium\",\n                \"question_count\": question_count,\n                \"assessment_type\": \"quiz\"\n            }\n            \n            questions = self.assessment_agent.generate_questions(assessment_data)\n            \n            # Validation criteria\n            validations = {\n                \"question_count\": self._validate_question_count(questions, question_count),\n                \"question_structure\": self._validate_question_structure(questions),\n                \"answer_options\": self._validate_answer_options(questions),\n                \"correct_answers\": self._validate_correct_answers(questions),\n                \"difficulty_appropriateness\": self._validate_difficulty_level(questions),\n                \"topic_relevance\": self._validate_topic_relevance(questions, topic)\n            }\n            \n            # Calculate overall score\n            scores = [v[\"score\"] for v in validations.values()]\n            overall_score = sum(scores) / len(scores)\n            \n            return {\n                \"topic\": topic,\n                \"overall_score\": overall_score,\n                \"validations\": validations,\n                \"passed\": overall_score >= 0.8,\n                \"questions\": questions\n            }\n            \n        except Exception as e:\n            return {\n                \"topic\": topic,\n                \"error\": str(e),\n                \"passed\": False\n            }\n    \n    def _validate_lesson_structure(self, lesson: Dict[str, Any]) -> Dict[str, Any]:\n        \"\"\"Validate that lesson has required sections\"\"\"\n        required_sections = [\"why_it_matters\", \"key_ideas\", \"examples\", \"pitfalls\", \"recap\"]\n        content = lesson.get(\"content\", {})\n        \n        missing_sections = []\n        for section in required_sections:\n            if section not in content or not content[section]:\n                missing_sections.append(section)\n        \n        score = (len(required_sections) - len(missing_sections)) / len(required_sections)\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.8,\n            \"details\": {\n                \"required_sections\": required_sections,\n                \"missing_sections\": missing_sections,\n                \"found_sections\": list(content.keys())\n            }\n        }\n    \n    def _validate_content_quality(self, lesson: Dict[str, Any]) -> Dict[str, Any]:\n        \"\"\"Validate the quality and depth of lesson content\"\"\"\n        content = lesson.get(\"content\", {})\n        \n        quality_checks = {\n            \"why_it_matters_length\": len(content.get(\"why_it_matters\", \"\")) >= 100,\n            \"key_ideas_count\": len(content.get(\"key_ideas\", [])) >= 3,\n            \"examples_provided\": len(content.get(\"examples\", [])) >= 1,\n            \"pitfalls_mentioned\": len(content.get(\"pitfalls\", [])) >= 1,\n            \"recap_comprehensive\": len(content.get(\"recap\", \"\")) >= 50\n        }\n        \n        passed_checks = sum(quality_checks.values())\n        score = passed_checks / len(quality_checks)\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.8,\n            \"details\": quality_checks\n        }\n    \n    def _validate_code_examples(self, lesson: Dict[str, Any]) -> Dict[str, Any]:\n        \"\"\"Validate code examples in the lesson\"\"\"\n        examples = lesson.get(\"content\", {}).get(\"examples\", [])\n        \n        if not examples:\n            return {\n                \"score\": 0.0,\n                \"passed\": False,\n                \"details\": {\"error\": \"No code examples found\"}\n            }\n        \n        code_quality_checks = []\n        for example in examples:\n            code = example.get(\"code\", \"\")\n            checks = {\n                \"has_code\": bool(code.strip()),\n                \"python_syntax\": self._check_python_syntax(code),\n                \"has_explanation\": bool(example.get(\"explanation\", \"\").strip()),\n                \"appropriate_length\": 10 <= len(code) <= 500\n            }\n            code_quality_checks.append(checks)\n        \n        # Calculate average score across all examples\n        if code_quality_checks:\n            total_score = 0\n            for checks in code_quality_checks:\n                example_score = sum(checks.values()) / len(checks)\n                total_score += example_score\n            score = total_score / len(code_quality_checks)\n        else:\n            score = 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.8,\n            \"details\": {\n                \"examples_count\": len(examples),\n                \"quality_checks\": code_quality_checks\n            }\n        }\n    \n    def _validate_educational_value(self, lesson: Dict[str, Any]) -> Dict[str, Any]:\n        \"\"\"Validate the educational value of the lesson\"\"\"\n        content = lesson.get(\"content\", {})\n        \n        educational_checks = {\n            \"clear_learning_objectives\": bool(content.get(\"why_it_matters\", \"\").strip()),\n            \"progressive_difficulty\": len(content.get(\"key_ideas\", [])) > 0,\n            \"practical_examples\": len(content.get(\"examples\", [])) > 0,\n            \"common_mistakes_addressed\": len(content.get(\"pitfalls\", [])) > 0,\n            \"reinforcement_provided\": bool(content.get(\"recap\", \"\").strip())\n        }\n        \n        score = sum(educational_checks.values()) / len(educational_checks)\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.8,\n            \"details\": educational_checks\n        }\n    \n    def _validate_language_clarity(self, lesson: Dict[str, Any]) -> Dict[str, Any]:\n        \"\"\"Validate language clarity and appropriateness\"\"\"\n        content = lesson.get(\"content\", {})\n        \n        # Combine all text content\n        all_text = \"\"\n        all_text += content.get(\"why_it_matters\", \"\") + \" \"\n        all_text += \" \".join(content.get(\"key_ideas\", [])) + \" \"\n        all_text += content.get(\"recap\", \"\") + \" \"\n        \n        for example in content.get(\"examples\", []):\n            all_text += example.get(\"explanation\", \"\") + \" \"\n        \n        clarity_checks = {\n            \"appropriate_length\": 200 <= len(all_text) <= 2000,\n            \"no_excessive_jargon\": self._check_jargon_level(all_text),\n            \"clear_sentences\": self._check_sentence_clarity(all_text),\n            \"beginner_friendly\": self._check_beginner_friendliness(all_text)\n        }\n        \n        score = sum(clarity_checks.values()) / len(clarity_checks)\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.7,  # Slightly lower threshold for language\n            \"details\": clarity_checks\n        }\n    \n    def _validate_question_count(self, questions: List[Dict], expected_count: int) -> Dict[str, Any]:\n        \"\"\"Validate that the correct number of questions were generated\"\"\"\n        actual_count = len(questions)\n        score = 1.0 if actual_count == expected_count else 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score == 1.0,\n            \"details\": {\n                \"expected\": expected_count,\n                \"actual\": actual_count\n            }\n        }\n    \n    def _validate_question_structure(self, questions: List[Dict]) -> Dict[str, Any]:\n        \"\"\"Validate the structure of generated questions\"\"\"\n        required_fields = [\"question\", \"options\", \"correct_answer\", \"explanation\"]\n        \n        structure_checks = []\n        for i, q in enumerate(questions):\n            checks = {}\n            for field in required_fields:\n                checks[f\"has_{field}\"] = field in q and q[field] is not None\n            \n            # Additional structure checks\n            checks[\"question_is_string\"] = isinstance(q.get(\"question\", \"\"), str)\n            checks[\"options_is_list\"] = isinstance(q.get(\"options\", []), list)\n            checks[\"correct_answer_is_int\"] = isinstance(q.get(\"correct_answer\"), int)\n            \n            structure_checks.append(checks)\n        \n        # Calculate average score\n        if structure_checks:\n            total_score = 0\n            for checks in structure_checks:\n                question_score = sum(checks.values()) / len(checks)\n                total_score += question_score\n            score = total_score / len(structure_checks)\n        else:\n            score = 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.9,\n            \"details\": {\n                \"questions_count\": len(questions),\n                \"structure_checks\": structure_checks\n            }\n        }\n    \n    def _validate_answer_options(self, questions: List[Dict]) -> Dict[str, Any]:\n        \"\"\"Validate the quality of answer options\"\"\"\n        option_checks = []\n        \n        for q in questions:\n            options = q.get(\"options\", [])\n            checks = {\n                \"has_four_options\": len(options) == 4,\n                \"options_not_empty\": all(opt.strip() for opt in options),\n                \"options_reasonable_length\": all(5 <= len(opt) <= 100 for opt in options),\n                \"options_distinct\": len(set(options)) == len(options)\n            }\n            option_checks.append(checks)\n        \n        # Calculate average score\n        if option_checks:\n            total_score = 0\n            for checks in option_checks:\n                question_score = sum(checks.values()) / len(checks)\n                total_score += question_score\n            score = total_score / len(option_checks)\n        else:\n            score = 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.8,\n            \"details\": option_checks\n        }\n    \n    def _validate_correct_answers(self, questions: List[Dict]) -> Dict[str, Any]:\n        \"\"\"Validate that correct answers are properly set\"\"\"\n        answer_checks = []\n        \n        for q in questions:\n            correct_answer = q.get(\"correct_answer\")\n            options = q.get(\"options\", [])\n            \n            checks = {\n                \"correct_answer_exists\": correct_answer is not None,\n                \"correct_answer_in_range\": isinstance(correct_answer, int) and 0 <= correct_answer < len(options),\n                \"has_explanation\": bool(q.get(\"explanation\", \"\").strip())\n            }\n            answer_checks.append(checks)\n        \n        # Calculate average score\n        if answer_checks:\n            total_score = 0\n            for checks in answer_checks:\n                question_score = sum(checks.values()) / len(checks)\n                total_score += question_score\n            score = total_score / len(answer_checks)\n        else:\n            score = 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.9,\n            \"details\": answer_checks\n        }\n    \n    def _validate_difficulty_level(self, questions: List[Dict]) -> Dict[str, Any]:\n        \"\"\"Validate that questions are at appropriate difficulty level\"\"\"\n        # This is a simplified check - in practice, you might use more sophisticated NLP\n        difficulty_indicators = {\n            \"beginner\": [\"what is\", \"define\", \"which of the following\", \"true or false\"],\n            \"intermediate\": [\"how would you\", \"what happens when\", \"compare\", \"analyze\"],\n            \"advanced\": [\"optimize\", \"implement\", \"design\", \"evaluate\"]\n        }\n        \n        difficulty_checks = []\n        for q in questions:\n            question_text = q.get(\"question\", \"\").lower()\n            \n            # Check if question contains appropriate difficulty indicators\n            has_beginner = any(indicator in question_text for indicator in difficulty_indicators[\"beginner\"])\n            has_intermediate = any(indicator in question_text for indicator in difficulty_indicators[\"intermediate\"])\n            \n            checks = {\n                \"appropriate_complexity\": len(question_text.split()) >= 5,  # Not too simple\n                \"not_too_complex\": len(question_text.split()) <= 30,  # Not too complex\n                \"has_clear_intent\": \"?\" in question_text or has_beginner or has_intermediate\n            }\n            difficulty_checks.append(checks)\n        \n        # Calculate average score\n        if difficulty_checks:\n            total_score = 0\n            for checks in difficulty_checks:\n                question_score = sum(checks.values()) / len(checks)\n                total_score += question_score\n            score = total_score / len(difficulty_checks)\n        else:\n            score = 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.7,\n            \"details\": difficulty_checks\n        }\n    \n    def _validate_topic_relevance(self, questions: List[Dict], topic: str) -> Dict[str, Any]:\n        \"\"\"Validate that questions are relevant to the topic\"\"\"\n        topic_keywords = topic.lower().split()\n        \n        relevance_checks = []\n        for q in questions:\n            question_text = q.get(\"question\", \"\").lower()\n            explanation = q.get(\"explanation\", \"\").lower()\n            \n            # Check if topic keywords appear in question or explanation\n            keyword_matches = sum(1 for keyword in topic_keywords if keyword in question_text or keyword in explanation)\n            \n            checks = {\n                \"contains_topic_keywords\": keyword_matches > 0,\n                \"question_length_appropriate\": 10 <= len(question_text) <= 200,\n                \"has_meaningful_explanation\": len(explanation) >= 20\n            }\n            relevance_checks.append(checks)\n        \n        # Calculate average score\n        if relevance_checks:\n            total_score = 0\n            for checks in relevance_checks:\n                question_score = sum(checks.values()) / len(checks)\n                total_score += question_score\n            score = total_score / len(relevance_checks)\n        else:\n            score = 0.0\n        \n        return {\n            \"score\": score,\n            \"passed\": score >= 0.7,\n            \"details\": relevance_checks\n        }\n    \n    def _check_python_syntax(self, code: str) -> bool:\n        \"\"\"Check if code has valid Python syntax\"\"\"\n        try:\n            compile(code, '<string>', 'exec')\n            return True\n        except SyntaxError:\n            return False\n    \n    def _check_jargon_level(self, text: str) -> bool:\n        \"\"\"Check if text has appropriate jargon level for beginners\"\"\"\n        # Simple heuristic: count technical terms\n        technical_terms = [\n            \"algorithm\", \"complexity\", \"optimization\", \"polymorphism\", \n            \"encapsulation\", \"inheritance\", \"abstraction\", \"recursion\"\n        ]\n        \n        jargon_count = sum(1 for term in technical_terms if term in text.lower())\n        word_count = len(text.split())\n        \n        # Allow some jargon but not too much\n        jargon_ratio = jargon_count / max(word_count, 1)\n        return jargon_ratio <= 0.05  # Max 5% jargon\n    \n    def _check_sentence_clarity(self, text: str) -> bool:\n        \"\"\"Check if sentences are clear and not too long\"\"\"\n        sentences = re.split(r'[.!?]+', text)\n        avg_sentence_length = sum(len(s.split()) for s in sentences) / max(len(sentences), 1)\n        \n        return avg_sentence_length <= 20  # Average sentence should be <= 20 words\n    \n    def _check_beginner_friendliness(self, text: str) -> bool:\n        \"\"\"Check if text is beginner-friendly\"\"\"\n        beginner_friendly_phrases = [\n            \"let's\", \"we'll\", \"you can\", \"for example\", \"simply\", \n            \"easy\", \"basic\", \"fundamental\", \"introduction\"\n        ]\n        \n        friendly_count = sum(1 for phrase in beginner_friendly_phrases if phrase in text.lower())\n        return friendly_count >= 1  # Should have at least one friendly phrase\n\ndef test_ai_quality_validation():\n    \"\"\"Run AI quality validation tests\"\"\"\n    print(\"🤖 Testing AI Response Quality Validation\")\n    print(\"=\" * 60)\n    \n    validator = AIQualityValidator()\n    \n    # Test topics\n    test_topics = [\n        \"Python Variables\",\n        \"Python Functions\",\n        \"Python Lists\"\n    ]\n    \n    lesson_results = []\n    assessment_results = []\n    \n    # Test lesson content quality\n    print(\"\\n📚 Testing Lesson Content Quality\")\n    for topic in test_topics:\n        result = validator.validate_lesson_content(topic)\n        lesson_results.append(result)\n        \n        if result.get(\"passed\"):\n            print(f\"✅ {topic}: {result['overall_score']:.2f}\")\n        else:\n            print(f\"❌ {topic}: {result.get('overall_score', 0):.2f}\")\n            if \"error\" in result:\n                print(f\"   Error: {result['error']}\")\n    \n    # Test assessment question quality\n    print(\"\\n📝 Testing Assessment Question Quality\")\n    for topic in test_topics:\n        result = validator.validate_assessment_questions(topic)\n        assessment_results.append(result)\n        \n        if result.get(\"passed\"):\n            print(f\"✅ {topic}: {result['overall_score']:.2f}\")\n        else:\n            print(f\"❌ {topic}: {result.get('overall_score', 0):.2f}\")\n            if \"error\" in result:\n                print(f\"   Error: {result['error']}\")\n    \n    # Summary\n    lesson_pass_rate = sum(1 for r in lesson_results if r.get(\"passed\", False)) / len(lesson_results)\n    assessment_pass_rate = sum(1 for r in assessment_results if r.get(\"passed\", False)) / len(assessment_results)\n    \n    print(f\"\\n📊 Quality Validation Summary:\")\n    print(f\"  Lesson Content Pass Rate: {lesson_pass_rate:.1%}\")\n    print(f\"  Assessment Questions Pass Rate: {assessment_pass_rate:.1%}\")\n    \n    overall_success = lesson_pass_rate >= 0.8 and assessment_pass_rate >= 0.8\n    \n    if overall_success:\n        print(\"\\n🎉 AI Quality Validation Tests Passed!\")\n        print(\"\\n✅ AI Content Quality Features:\")\n        print(\"  - Lesson structure validation (required sections)\")\n        print(\"  - Content quality assessment (depth and completeness)\")\n        print(\"  - Code example validation (syntax and clarity)\")\n        print(\"  - Educational value assessment\")\n        print(\"  - Language clarity and beginner-friendliness\")\n        print(\"  - Assessment question structure validation\")\n        print(\"  - Answer option quality checks\")\n        print(\"  - Topic relevance verification\")\n        print(\"  - Difficulty level appropriateness\")\n    else:\n        print(\"\\n❌ AI Quality Validation Tests Failed!\")\n        print(f\"  Lesson pass rate: {lesson_pass_rate:.1%} (need ≥80%)\")\n        print(f\"  Assessment pass rate: {assessment_pass_rate:.1%} (need ≥80%)\")\n    \n    return overall_success\n\nif __name__ == \"__main__\":\n    success = test_ai_quality_validation()\n    sys.exit(0 if success else 1)\n"